mapper.select:
select ifnull(sum(should_pay), 0)
from mvp_group_customer
where group_id = #{groupId}

select
    greatest(
        ifnull(sum(fr.amount), 0) - ifnull((
            select sum(s2.paid_amount)
            from mvp_advance_settlement s2
            where s2.user_id = #{userId}
              and s2.settle_month = #{settleMonth}
        ), 0),
        0
    )
from mvp_finance_record fr
where fr.record_type = 2
  and fr.status = 1
  and fr.advance_user_id = #{userId}
  and date_format(fr.occur_date, '%Y-%m') = #{settleMonth}

select ifnull(sum(fr.amount), 0)
from mvp_finance_record fr
where fr.record_type = 2
  and fr.status = 1
  and fr.advance_user_id = #{userId}
  and date_format(fr.occur_date, '%Y-%m') = #{settleMonth}

select ifnull(sum(paid_amount), 0)
from mvp_advance_settlement
where user_id = #{userId}
  and settle_month = #{settleMonth}
